+fn atc_agent_state_color(state: &str, tp: &TuiThemePalette) -> ftui::PackedRgba {
+    if state.eq_ignore_ascii_case("dead") {
+        tp.severity_error
+    } else if state.eq_ignore_ascii_case("flaky") {
+        tp.severity_warn
+    } else {
+        tp.severity_ok
+    }
+}
