+    if !snapshot.enabled {
+        "Disabled"
+    } else if snapshot.source == "warming_up" {
+        "Warmup"
+    } else if snapshot.source == "spawn_failed" {
+        "Failed"
+    } else if snapshot.source == "live" {
+        "Live"
+    } else {
+        "Fallback"
+    }
+}
