+fn atc_availability_color(
+    snapshot: &AtcOperatorSnapshot,
+    tp: &TuiThemePalette,
+) -> ftui::PackedRgba {
+    if !snapshot.enabled {
+        tp.text_disabled
+    } else if snapshot.source == "spawn_failed" {
+        tp.severity_error
+    } else if snapshot.source == "live" {
+        tp.severity_ok
+    } else {
