+fn format_timestamp_compact(timestamp_micros: i64) -> String {
+    if timestamp_micros <= 0 {
+        return "--".to_string();
+    }
+    let iso = mcp_agent_mail_db::micros_to_iso(timestamp_micros);
+    iso.replace('T', " ").chars().take(19).collect()
+}
